"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[48369],{48403(e){e.exports=JSON.parse('{"tag":{"label":"Dashboard","permalink":"/sdk/4.6.0/tags/dashboard","allTagsPath":"/sdk/4.6.0/tags","count":4,"items":[{"id":"guides/creating-workspaces-guide","title":"Creating Workspaces Guide","description":"Guide for creating ServiceNow Workspaces -- complete out-of-the-box solutions for managing business entities through standardized CRUD workflows. A workspace automatically generates a dashboard page, list management views, and detailed forms following ServiceNow\'s standard UX patterns.","permalink":"/sdk/4.6.0/guides/creating-workspaces-guide"},{"id":"api/workspace/dashboard-api","title":"Dashboard","description":"Creates a Dashboard -- a configurable layout of widgets organized into tabs for data visualization and reporting (par_dashboard). Dashboards support drag-and-drop widget positioning, tab-based organization, role-based permissions, and group/user visibility controls.","permalink":"/sdk/4.6.0/api/workspace/dashboard-api"},{"id":"guides/atf-guide","title":"Implementing Tests Guide","description":"Create ServiceNow Automated Test Framework (ATF) test cases using Fluent APIs across 11 ATF categories: server, form, REST, catalog, email, app navigator, reporting, responsive dashboard, and Service Portal variants (formSP, catalogSP). This guide covers test strategy, category selection, step configuration, and the full API surface for each ATF namespace.","permalink":"/sdk/4.6.0/guides/atf-guide"},{"id":"guides/ui-page-guide","title":"UI Pages","description":"Guide for creating ServiceNow UI Pages using React and the Fluent DSL. UI Pages are custom React-based interfaces for building forms, dashboards, list views, multi-step wizards, and any custom web experience within ServiceNow. They use React 18.2.0, the @servicenow/react-components library, Table API integration, CSS styling, and SPA routing via URLSearchParams.","permalink":"/sdk/4.6.0/guides/ui-page-guide"}],"unlisted":false}}')}}]);